static inline gps_location_t get_location(void)
{
    gps_location_t loc;
    pthread_mutex_lock(&g_telem_lock);
    loc.lat        = g_telem.lat;
    loc.lon        = g_telem.lon;
    loc.alt_msl_m  = g_telem.alt_msl_m;
    loc.alt_rel_m  = g_telem.alt_rel_m;
    loc.valid      = g_telem.have_global_pos;
    pthread_mutex_unlock(&g_telem_lock);
    return loc;
}

