static inline bool ekf_ok(void)
{
    pthread_mutex_lock(&g_telem_lock);
    bool v = g_telem.ekf_ok;
    pthread_mutex_unlock(&g_telem_lock);
    return v;
}

/* heartbeat_ok()
 *   True if a HEARTBEAT arrived within the last 3 heartbeat periods -
 *   the same freshness window PX4 itself uses to judge link loss. */
static inline bool heartbeat_ok(void)
{
    pthread_mutex_lock(&g_telem_lock);
    bool have = g_telem.have_heartbeat;
    struct timespec last = g_telem.last_heartbeat;
    pthread_mutex_unlock(&g_telem_lock);
    if (!have) return false;

    struct timespec now;
    clock_gettime(CLOCK_MONOTONIC, &now);
    long age_ms = (now.tv_sec - last.tv_sec) * 1000L + (now.tv_nsec - last.tv_nsec) / 1000000L;
    return age_ms <= (3 * SDK_HEARTBEAT_PERIOD_MS);
}

static inline home_position_t get_home(void)
{
    pthread_mutex_lock(&g_telem_lock);
    home_position_t h = g_telem.home;
    pthread_mutex_unlock(&g_telem_lock);
    return h;
}

static inline system_status_t get_status(void)
{
    system_status_t s;
    pthread_mutex_lock(&g_telem_lock);
    s.armed          = g_telem.armed;
    s.ekf_ok         = g_telem.ekf_ok;
    s.mode           = sdk_px4_to_flight_mode(g_telem.custom_mode);
    s.system_status  = g_telem.system_status_raw;
    pthread_mutex_unlock(&g_telem_lock);
    s.heartbeat_ok   = heartbeat_ok();
    return s;
}

/* mission_time()
 *   Milliseconds since start(). */
static inline long mission_time(void)
{
    return sdk_now_ms_since_start();
}

/* flight_time()
 *   Milliseconds since the vehicle became armed. Returns 0 while
 *   disarmed (no dedicated "armed since" MAVLink message is cached,
 *   so this reads the same clock mission_time() does and is only
 *   meaningful once armed). */
static inline long flight_time(void)
{
    return is_armed() ? sdk_now_ms_since_start() : 0;
}

static inline rc_channels_t get_rc(void)
{
    pthread_mutex_lock(&g_telem_lock);
    rc_channels_t rc = g_telem.rc;
    pthread_mutex_unlock(&g_telem_lock);
    return rc;
}

/* link_quality()
 *   0-100 heuristic: 100 while heartbeat_ok(), 0 once it goes stale.
 *   MAVLink has no standard "signal quality" scalar over a wired/USB
 *   link, so this reflects link liveness rather than RF quality. */
static inline int link_quality(void)
{
    return heartbeat_ok() ? 100 : 0;
}

#endif /* SDK_API_TELEMETRY_H */
